# ## Router Evals using LLM-as-a-Judge

# To evaluate the router, you will use this template provided by Phoenix to the LLM-as-a-Judge. 

# In[ ]:


print(TOOL_CALLING_PROMPT_TEMPLATE)


# ### Querying the Required Spans

# In[ ]:


query = SpanQuery().where(
    "span_kind == 'LLM'",
).select(
    question="input.value",
    tool_call="output.value"
)

# The Phoenix Client can take this query and return the dataframe.
tool_calls_df = phoenix_client.spans.get_spans_dataframe(query=query, 
                                        project_identifier=PROJECT_NAME, 
                                        timeout=None)
tool_calls_df = tool_calls_df.dropna(subset=["tool_call"])
tool_calls_df = tool_calls_df[tool_calls_df["tool_call"].str.contains("FunctionCall", na=False)]

tool_calls_df.head()


# ### Evaluating Tool Calling

# In[ ]:


with suppress_tracing():
    tool_call_evaluator = create_classifier(
        name="tool_call",
        prompt_template=TOOL_CALLING_PROMPT_TEMPLATE.replace("{tool_definitions}", json.dumps(tool_schemas).replace("{", '"').replace("}", '"')),
        llm=LLM(provider="google", model="gemini-2.5-flash"),
        choices=['correct', 'incorrect']
    )
    if not tool_calls_df.empty:
        eval_results_df = evaluate_dataframe(dataframe=tool_calls_df, evaluators=[tool_call_evaluator])
    else:
        eval_results_df = pd.DataFrame()

tool_call_eval = pd.DataFrame(index=eval_results_df.index)
if not eval_results_df.empty and 'tool_call_score' in eval_results_df.columns:
    tool_call_eval['label'] = eval_results_df['tool_call_score'].apply(lambda x: x.get('label') if isinstance(x, dict) else None)
    tool_call_eval['explanation'] = eval_results_df['tool_call_score'].apply(lambda x: x.get('explanation') if isinstance(x, dict) else None)
    tool_call_eval['score'] = tool_call_eval['label'].apply(lambda x: 1.0 if x == 'correct' else 0.0)
else:
    tool_call_eval['label'] = []
    tool_call_eval['explanation'] = []
    tool_call_eval['score'] = []

tool_call_eval.head()


# In[ ]:


if not tool_call_eval.empty:
    phoenix_client.spans.log_span_annotations_dataframe(
        dataframe=tool_call_eval,
        annotation_name="Tool Calling Eval",
        annotator_kind="LLM"
    )


# ## Evaluating Python Code Gen (Tool 3 - Data Visualization Evals)

# In[ ]:


query = SpanQuery().where(
    "name =='create_chart_llm'"
).select(
    generated_code="output.value"
)

# The Phoenix Client can take this query and return the dataframe.
code_gen_df = phoenix_client.spans.get_spans_dataframe(query=query, 
                                      project_identifier=PROJECT_NAME, 
                                      timeout=None)

code_gen_df.head()


# In[ ]:


def code_is_runnable(output: str) -> bool:
    """Check if the code is runnable"""
    output = output.strip()
    output = output.replace("```python", "").replace("```", "")
    try:
        exec(output)
        return True
    except Exception as e:
        return False


# In[ ]:


if not code_gen_df.empty and "generated_code" in code_gen_df.columns:
    code_gen_df["label"] = code_gen_df["generated_code"].apply(code_is_runnable).map({True: "runnable", False: "not_runnable"})
    code_gen_df["score"] = code_gen_df["label"].map({"runnable": 1, "not_runnable": 0})
else:
    code_gen_df["label"] = []
    code_gen_df["score"] = []


# In[ ]:


code_gen_df.head()


# In[ ]:


if not code_gen_df.empty:
    phoenix_client.spans.log_span_annotations_dataframe(
        dataframe=code_gen_df,
        annotation_name="Runnable Code Eval",
        annotator_kind="LLM"
    )


# ## Evaluating Analysis Clarity (Tool 2 - Data Analysis Evals)

# In[ ]:


CLARITY_LLM_JUDGE_PROMPT = """
In this task, you will be presented with a query and an answer. Your objective is to evaluate the clarity 
of the answer in addressing the query. A clear response is one that is precise, coherent, and directly 
addresses the query without introducing unnecessary complexity or ambiguity. An unclear response is one 
that is vague, disorganized, or difficult to understand, even if it may be factually correct.

Your response should be a single word: either "clear" or "unclear," and it should not include any other 
text or characters. "clear" indicates that the answer is well-structured, easy to understand, and 
appropriately addresses the query. "unclear" indicates that some part of the response could be better 
structured or worded.
Please carefully consider the query and answer before determining your response.

After analyzing the query and the answer, you must write a detailed explanation of your reasoning to 
justify why you chose either "clear" or "unclear." Avoid stating the final label at the beginning of your 
explanation. Your reasoning should include specific points about how the answer does or does not meet the 
criteria for clarity.

[BEGIN DATA]
Query: {query}
Answer: {response}
[END DATA]
Please analyze the data carefully and provide an explanation followed by your response.

EXPLANATION: Provide your reasoning step by step, evaluating the clarity of the answer based on the query.
LABEL: "clear" or "unclear"
"""


# In[ ]:


query = SpanQuery().where(
    "span_kind=='AGENT'"
).select(
    response="output.value",
    query="input.value"
)

# The Phoenix Client can take this query and return the dataframe.
clarity_df = phoenix_client.spans.get_spans_dataframe(query=query, 
                                     project_identifier=PROJECT_NAME,
                                     timeout=None)

clarity_df.head()


# In[ ]:


with suppress_tracing():
    clarity_evaluator = create_classifier(
        name="clarity",
        prompt_template=CLARITY_LLM_JUDGE_PROMPT,
        llm=LLM(provider="google", model="gemini-2.5-flash"),
        choices=['clear', 'unclear']
    )
    if not clarity_df.empty:
        eval_results_df = evaluate_dataframe(dataframe=clarity_df, evaluators=[clarity_evaluator])
    else:
        eval_results_df = pd.DataFrame()

clarity_eval = pd.DataFrame(index=eval_results_df.index)
if not eval_results_df.empty and 'clarity_score' in eval_results_df.columns:
    clarity_eval['label'] = eval_results_df['clarity_score'].apply(lambda x: x.get('label') if isinstance(x, dict) else None)
    clarity_eval['explanation'] = eval_results_df['clarity_score'].apply(lambda x: x.get('explanation') if isinstance(x, dict) else None)
    clarity_eval['score'] = clarity_eval['label'].apply(lambda x: 1.0 if x == 'clear' else 0.0)
else:
    clarity_eval['label'] = []
    clarity_eval['explanation'] = []
    clarity_eval['score'] = []

clarity_eval.head()


# In[ ]:


if not clarity_eval.empty:
    phoenix_client.spans.log_span_annotations_dataframe(
        dataframe=clarity_eval,
        annotation_name="Response Clarity",
        annotator_kind="LLM"
    )


