# In[ ]:

def export_trace_to_ascii():
    print("Exporting traces and evaluations to ASCII...")
    import datetime
    
    try:
        # Combine all evaluation results
        eval_dfs = []
        if not tool_call_eval.empty:
            tc_eval = tool_call_eval.copy()
            tc_eval['eval_type'] = "Tool Calling Accuracy"
            eval_dfs.append(tc_eval)
        if not code_gen_df.empty:
            code_eval = pd.DataFrame(index=code_gen_df.index)
            code_eval['label'] = code_gen_df['label']
            code_eval['explanation'] = "Code execution failed." # default explanation
            code_eval.loc[code_eval['label'] == 'runnable', 'explanation'] = None
            code_eval['eval_type'] = "Python Code Generation & Execution"
            eval_dfs.append(code_eval)
        if not clarity_eval.empty:
            cl_eval = clarity_eval.copy()
            cl_eval['eval_type'] = "Response Clarity & Helpfulness"
            eval_dfs.append(cl_eval)
        if not sql_gen_eval.empty:
            sq_eval = sql_gen_eval.copy()
            sq_eval['eval_type'] = "SQL Query Generation Accuracy"
            eval_dfs.append(sq_eval)
            
        all_evals = pd.concat(eval_dfs) if eval_dfs else pd.DataFrame()

        df = phoenix_client.spans.get_spans_dataframe(project_identifier=PROJECT_NAME)
        if df is None or df.empty:
            print("No traces found to export to ASCII.")
            return

        df = df.sort_values(by='start_time')
        
        seq_map = {}
        for i, idx in enumerate(df.index):
            seq_map[idx] = i + 1

        children_map = {}
        roots = []
        for index, row in df.iterrows():
            parent_id = row.get('parent_id')
            if pd.isna(parent_id) or parent_id == '' or parent_id not in df.index:
                roots.append(index)
            else:
                if parent_id not in children_map:
                    children_map[parent_id] = []
                children_map[parent_id].append(index)

        lines = []
        def build_tree(node_id, prefix="", is_last=True, is_root=False):
            row = df.loc[node_id]
            seq = seq_map[node_id]
            name = row.get('name', 'Unknown')
            kind = row.get('span_kind', '')
            status = row.get('status_code', 'OK')
            
            # Check for evaluation
            eval_str = ""
            if not all_evals.empty and node_id in all_evals.index:
                eval_row = all_evals.loc[node_id]
                if isinstance(eval_row, pd.DataFrame):
                    eval_row = eval_row.iloc[0]
                
                label = eval_row.get('label')
                explanation = eval_row.get('explanation')
                eval_type = eval_row.get('eval_type', 'Evaluation')
                
                # Determine branch indentation for the multi-line evaluation summary
                eval_indent = f"\n{prefix}{'    ' if is_last else '│   '}    └── Evaluation Type: {eval_type}"
                
                if label in ['incorrect', 'not_runnable', 'unclear']:
                    if explanation:
                        try:
                            from google import genai
                            client = genai.Client()
                            response = client.models.generate_content(
                                model='gemini-2.5-flash',
                                contents=f"Summarize this failure reason in one short, clear sentence (maximum 15 words): {explanation}"
                            )
                            reason = response.text.strip().replace('\\n', ' ')
                        except Exception:
                            reason_parts = str(explanation).split('.')[:2]
                            reason = '. '.join(p.replace('\\n', ' ').strip() for p in reason_parts if p.strip())
                            reason = reason + "." if reason else "Evaluation failed."
                    else:
                        reason = "Evaluation failed."
                    eval_str = f" [EVAL FAILED: {label}] - Reason: {reason}{eval_indent}"
                elif label:
                    eval_str = f" [EVAL PASSED: {label}]{eval_indent}"

            node_str = f"[{seq}] {name} ({kind}) [Status: {status}]{eval_str}"
            
            if is_root:
                lines.append(node_str)
                next_prefix = ""
            else:
                branch = "└── " if is_last else "├── "
                lines.append(f"{prefix}{branch}{node_str}")
                next_prefix = prefix + ("    " if is_last else "│   ")
                
            children = children_map.get(node_id, [])
            for i, child_id in enumerate(children):
                build_tree(child_id, next_prefix, i == (len(children) - 1), False)

        for root in roots:
            build_tree(root, is_root=True)

        timestamp = datetime.datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
        filename = f"trace_visualization_ascii_{timestamp}.txt"
        
        with open(filename, "w") as f:
            f.write("\n".join(lines))
            
        print(f"ASCII trace with evaluations successfully exported to {filename}")

    except Exception as e:
        print(f"Failed to export trace to ASCII: {e}")

export_trace_to_ascii()




